import{_ as r,o as a,c as t,a3 as o}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"Search in Notely","description":"Learn how to perform global searches, use regex patterns, filter by code blocks, and utilize semantic AI search.","frontmatter":{"title":"Search in Notely","description":"Learn how to perform global searches, use regex patterns, filter by code blocks, and utilize semantic AI search.","keywords":"search, global search, regex, regular expressions, code block search, semantic search, synonyms","category":"Search"},"headers":[],"relativePath":"search.md","filePath":"search.md","lastUpdated":1784665499000}'),s={name:"search.md"};function n(i,e,l,c,h,d){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h1><p>Search is a first-class feature in Notely. You can search within the current note, across the entire workspace, or filter for specific content types.</p><h2 id="_1-find-in-current-note" tabindex="-1">1. Find in Current Note <a class="header-anchor" href="#_1-find-in-current-note" aria-label="Permalink to &quot;1. Find in Current Note&quot;">​</a></h2><p>Press <strong><code>Ctrl + F</code></strong> to open the in-note search bar:</p><ul><li>Search by keyword.</li><li>Jump through matches using <strong>Next</strong> (<code>F3</code>) and <strong>Previous</strong> (<code>Shift + F3</code>).</li><li>Case-sensitivity and whole-word matching toggles are supported.</li></ul><p>Press <strong><code>Ctrl + H</code></strong> to open Find and Replace.</p><hr><h2 id="_2-global-workspace-search" tabindex="-1">2. Global Workspace Search <a class="header-anchor" href="#_2-global-workspace-search" aria-label="Permalink to &quot;2. Global Workspace Search&quot;">​</a></h2><p>Press <strong><code>Ctrl + Shift + F</code></strong> to open the Global Search panel:</p><ul><li>Searches all <code>.md</code> note titles, folders, metadata, and note content.</li><li>Results update instantly as you type.</li><li>Matches are shown with content snippets highlighting where the term appeared.</li></ul><h3 id="synonym-term-support" tabindex="-1">Synonym &amp; Term Support <a class="header-anchor" href="#synonym-term-support" aria-label="Permalink to &quot;Synonym &amp; Term Support&quot;">​</a></h3><p>Search matches related concepts even if the exact keyword differs. Searching for:</p><ul><li><strong>Repository</strong>, <strong>Repo</strong>, <strong>Git</strong>, <strong>Version Control</strong>, <strong>Commit</strong>, <strong>History</strong>, <strong>Diff</strong></li><li>will all surface related version control documentation and notes.</li></ul><hr><h2 id="_3-regular-expression-search-regex" tabindex="-1">3. Regular Expression Search (Regex) <a class="header-anchor" href="#_3-regular-expression-search-regex" aria-label="Permalink to &quot;3. Regular Expression Search (Regex)&quot;">​</a></h2><p>Enable advanced matching by clicking the <strong><code>.*</code></strong> button in the search bar:</p><ul><li>Search using standard regular expression patterns.</li><li>Notely checks your regex syntax live and shows a warning if the pattern is invalid.</li></ul><p><strong>Common Regex Examples:</strong></p><ul><li>Find functions: <code>function\\s+\\w+\\s*\\(</code></li><li>Find issue IDs: <code>Error: \\[[A-Z0-9_]+\\]</code></li><li>Find markdown links: <code>\\[([^\\]]+)\\]\\(([^)]+)\\)</code></li></ul><hr><h2 id="_4-code-block-search" tabindex="-1">4. Code Block Search <a class="header-anchor" href="#_4-code-block-search" aria-label="Permalink to &quot;4. Code Block Search&quot;">​</a></h2><p>Filter your search results to code snippets only:</p><ol><li>Click the <strong>Code Blocks</strong> filter in the global search panel.</li><li>Enter your keyword or regex.</li><li>Notely will only return matches found inside fenced code blocks (<code>```</code>).</li></ol><hr><h2 id="_5-semantic-search-ai-powered" tabindex="-1">5. Semantic Search (AI-Powered) <a class="header-anchor" href="#_5-semantic-search-ai-powered" aria-label="Permalink to &quot;5. Semantic Search (AI-Powered)&quot;">​</a></h2><p>When AI embeddings are configured, Notely supports meaning-based search:</p><ul><li>Matches concepts rather than exact words (e.g. searching &quot;backup&quot; finds notes discussing &quot;disaster recovery&quot; or &quot;exporting&quot;).</li><li>Requires the <strong>Generate Embeddings</strong> toggle to be enabled in AI settings.</li><li>The status bar displays the freshness state of the search index.</li></ul><p>→ <a href="/ai/setup.html">AI Setup &amp; Embeddings</a></p>',28)])])}const g=r(s,[["render",n]]);export{u as __pageData,g as default};
